#!/usr/bin/env node
import { program } from 'commander';
import { hello } from './commands/hello.js';

program
  .name('{{commandName}}')
  .description('{{description}}')
  .version('0.1.0');

program
  .command('hello')
  .description('인사 메시지 출력')
  .argument('[name]', '이름', 'World')
  .action(hello);

program.parse();
